head.script:
scwin.arrRtnVal = [];
scwin.bOptDisableTF = "";

scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    if (scwin.params != null) {
        if (scwin.params.bOptDisableTF != null) {
            scwin.bOptDisableTF = scwin.params.bOptDisableTF;
        }
    }
};

scwin.f_FieldClear = function() {
    if (scwin.bOptDisableTF == "T") return;
    $c.gus.cfInitObjects(tbl_search, null);
    ed_resultdt.setFocus();
};

scwin.f_WinClose = function() {
    scwin.arrRtnVal[0] = "N/A";
    scwin.arrRtnVal[1] = ed_resultdt.getValue().trim();

    $c.win.closePopup(scwin.arrRtnVal);
};

scwin.f_OpenCommonPopUp = function(disGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    let rtnList = [];

    switch (disGubun) {
        case "oldDepartmentA":
            udc_olddept.ilCommonPopUp(scwin.callbackOldDepartmentA,
                ed_olddept.getValue().trim(),
                txt_olddeptnm.getValue(),
                pWinCloseTF,
                '2',
                "Code, Name",
                '80,230',
                "3,4,5,6,7,8,9,10",
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearchTF,
                "Department,Code,Name",
                pNoDataCloseTF
            );
            break;
        case "newDepartment":
            udc_newdept.ilCommonPopUp(scwin.callbackNewDepartment,
                ed_newdept.getValue().trim(),
                txt_newdeptnm.getValue(),
                pWinCloseTF,
                '2',
                "Code, Name",
                '80,230',
                "3,4,5,6,7,8,9,10",
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearchTF,
                "Department,Code,Name",
                pNoDataCloseTF
            );
            break;
        default:
            break;
    }
};

scwin.callbackOldDepartmentA = function(rtnList) {
    if (typeof(rtnList) != "undefined") {
        if (rtnList[0] != "N/A") {
            $c.gus.cfSetReturnValue(rtnList, ed_olddept, txt_olddeptnm);
        }
    }
};

scwin.callbackNewDepartment = function(rtnList) {
    if (typeof(rtnList) != "undefined") {
        if (rtnList[0] != "N/A") {
            $c.gus.cfSetReturnValue(rtnList, ed_newdept, txt_newdeptnm);
        }
    } else {
        ed_newdept.setValue("");
        txt_newdeptnm.setValue("");
    }
};

scwin.ed_newdept_onblur = function(e) {
    let strClntNo = ed_newdept.getValue().trim();

    if (strClntNo.length > 0) {
        txt_newdeptnm.setValue("");
        scwin.f_OpenCommonPopUp("newDepartment", "T", "F", "F");
    } else {
        txt_newdeptnm.setValue("");
    }
};

scwin.btn_trigger2_onclick = function(e) {
    scwin.f_WinClose();
};
